// bucket.js
import { db } from "../../firebase";
import { collection, doc, getDoc, getDocs, addDoc, updateDoc, deleteDoc } from "firebase/firestore";
import { async } from "@firebase/util";

// Actions
const LOAD = 'bucket/LOAD';
const CREATE = 'bucket/CREATE';
const DELETE = 'bucket/DELETE';
const UPDATE = 'bucket/UPDATE';
const LOADED = "bucket/LOADED";

const initialState = {
  is_loaded: false,
  list: [],
  // list: ["영화관 가기", "매일 책읽기", "수영 배우기", "코딩하기"],
};

// Action Creators

// 딕셔너리에서 키랑 벨류가 똑같으면 생략 가능  
export function loadBucket(bucket_list) {
  return { type: LOAD, bucket_list };
}

export function createBucket(newBucket) {
  return {type: CREATE, newBucket: newBucket};
}

export function deleteBucket(bucket_index) {
  return { type: DELETE, bucket_index };
}

export function updateBucket(bucket_index) {
  return { type: UPDATE, bucket_index };
}

export function isLoaded(loaded) {
  return { type: LOADED, loaded };
}

// Middlewares
export const loadBucketFB = () => {
  // 파이어스토어에서 가져오는건 비동기 통신이기 때문에 async, await 사용 필요
  return async function (dispatch) {
    const bucket_data = await getDocs(collection(db, "bucket"));

    let bucket_list = [];

    bucket_data.forEach((b) => {
      // bucket_list = [...bucket_list, { ...b.data() }];
      bucket_list.push({ id:b.id, ...b.data() });
    });

    dispatch(loadBucket(bucket_list));
  }
}

export const addBucketFB = (bucket) => {
  // addBucketlist() 가 뭘 넘겨주는지 보고 인자로 받으면 됨.
  return async function (dispatch) {
    dispatch(isLoaded(false));
    const docRef = await addDoc(collection(db, "bucket"), bucket);
    // const _bucket = await getDoc(docRef);
    const bucket_data = { id: docRef.id, ...bucket };

    // firestore에서 업데이트 완료 후, 리덕스에서도 업뎃 해줘야 함
    dispatch(createBucket(bucket_data));
  }
}

export const updateBucketFB = (bucket_id) => {
  return async function (dispatch, getState) {
    const docRef = doc(db, "bucket", bucket_id);
    await updateDoc(docRef, { completed: true });

    console.log(getState().bucket);
    const _bucket_list = getState().bucket.list;
    const bucket_index = _bucket_list.findIndex((b) => {
      return b.id === bucket_id;
    });

    dispatch(updateBucket(bucket_index));
  }
}

export const deleteBucketFB = (bucket_id) => {
  return async function (dispatch, getState) {
    // 파라미터가 필수인 곳에 오류 났을 때 메세지 주면 좋음
    if (!bucket_id) {
      window.alert("There is no ID");
      return;
    }

    dispatch(isLoaded(false));
    const docRef = doc(db, "bucket", bucket_id);
    await deleteDoc(docRef);

    // 현재 인덱스 찾기
    const _bucket_list = getState().bucket.list;
    const bucket_index = _bucket_list.findIndex((b) => {
      return b.id === bucket_id;
    });

    dispatch(deleteBucket(bucket_index));
  }
}


// Reducer
export default function reducer(state = initialState, action = {}) {
  switch (action.type) {
    // do reducer stuff
    case "bucket/LOAD": {
      return {list: action.bucket_list, is_loaded: true,};
    }

    case "bucket/CREATE": {
      const new_bucket_list = [...state.list, action.newBucket];
      return {...state, list: new_bucket_list, is_loaded: true};
    }
    case "bucket/DELETE": {
      const new_bucket_list = state.list.filter((lst, idx) => {
        return parseInt(action.bucket_index) !== idx;
      });
      return {...state, list: new_bucket_list, is_loaded: true};
    }
    case "bucket/UPDATE": {
      const new_bucket_list = state.list.map((l, idx) => {
        if (parseInt(action.bucket_index) === idx) {
          return { ...l, completed: true };
        } else {
          return l;
        }
      })
      return {...state, list: new_bucket_list};
    }
      
    case "bucket/LOADED": {
      return { ...state, is_loaded: action.loaded };
    }
    case "bucket/DELETED": {
      return { ...state, is_loaded: action.loaded };
      }

    default: return state;
  }
}